import React, { useState } from "react";
import "./Men.css";

const menProducts = [
    {
        id: 1,
        name: "Men Casual Shirt",
        price: 45,
        image: "/images/men/men1.jpg",
    },
    {
        id: 2,
        name: "Men Formal Shirt",
        price: 55,
        image: "/images/men/men2.jpg",
    },
    {
        id: 3,
        name: "Men T-Shirt",
        price: 35,
        image: "/images/men/men3.jpg",
    },
    {
        id: 4,
        name: "Men Jeans",
        price: 60,
        image: "/images/men/men4.jpg",
    },
    {
        id: 5,
        name: "Men Jacket",
        price: 85,
        image: "/images/men/men5.jpg",
    },
    {
        id: 6,
        name: "Men Hoodie",
        price: 70,
        image: "/images/men/men6.jpg",
    },
];

const Men = () => {
    const [quantity, setQuantity] = useState({});

    const increaseQty = (id) => {
        setQuantity((prev) => ({
            ...prev,
            [id]: (prev[id] || 0) + 1,
        }));
    };

    const decreaseQty = (id) => {
        setQuantity((prev) => ({
            ...prev,
            [id]: prev[id] > 0 ? prev[id] - 1 : 0,
        }));
    };

    return (
        <div className="men-page">
            <h2 className="men-title">Men Collection</h2>

            <div className="men-image-box">
                <img src={product.image} alt={product.name} />
            </div>


            <div className="men-grid">
                {menProducts.map((item) => (
                    <div className="men-card" key={item.id}>
                        <img src={item.image} alt={item.name} />

                        <div className="men-info">
                            <h3>{item.name}</h3>
                            <p className="price">${item.price}</p>

                            <div className="qty-box">
                                <button onClick={() => decreaseQty(item.id)}>-</button>
                                <span>{quantity[item.id] || 0}</span>
                                <button onClick={() => increaseQty(item.id)}>+</button>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Men;
